cd /home/polaris/wt/flywheel && python3 -c "
import json
W={}
for line in open('third_party/deep_research_bench/data/criteria_data/criteria.jsonl'):
    d=json.loads(line)
    if d['id']!=72: continue
    dw=d['dimension_weight']
    for dim,items in d['criterions'].items():
        for c in items: W[c['criterion']]=dw[dim]*c['weight']
    break

def led(f):
    d=json.load(open(f)); o={}
    for dim,items in (d['judge_output'] or {}).items():
        if isinstance(items,list):
            for c in items: o[c['criterion']]=(c['article_1_score'],c['article_2_score'])
    return o
US,BO,CE=led('outputs/judge_feedback.json'),led('outputs/judge_feedback_bodhi.json'),led('outputs/judge_feedback_cellcog.json')

def tot(l,i): return sum(W[k]*v[i] for k,v in l.items())
T,R=tot(US,0),tot(US,1)
print(f'BASELINE  T={T:.3f} R={R:.3f}  S={T/(T+R):.4f}')
print(f'CELLCOG   T={tot(CE,0):.3f} R={tot(CE,1):.3f}  S={tot(CE,0)/(tot(CE,0)+tot(CE,1)):.4f}')
print()
print('PER-CRITERION REFERENCE DRIFT (R_vs_us -> R_vs_cellcog). Positive = judge marks REF UP as target improves.')
print(f\"{'w':>6} {'us':>4} {'cell':>5} {'Rus':>4} {'Rcell':>5} {'dR':>5}  criterion\")
rows=[]
for k in sorted(W,key=lambda x:-W[x]):
    dR=CE[k][1]-US[k][1]
    rows.append((W[k],US[k][0],CE[k][0],US[k][1],CE[k][1],dR,k))
for w,u,c,ru,rc,dr,k in rows:
    flag=' <<< REF RISES' if dr>0.5 else ''
    print(f'{w:.4f} {u:4.1f} {c:5.1f} {ru:4.1f} {rc:5.1f} {dr:+5.1f}  {k[:46]}{flag}')
print()
sumdR=sum(w*dr for w,_,_,_,_,dr,_ in rows)
print(f'WEIGHTED dR (us->cellcog operating point) = {sumdR:+.3f}   (i.e. R: {R:.3f} -> {R+sumdR:.3f})')
"

